<?php
declare(strict_types=1);
require_once __DIR__ . '/../includes/app-layout.php';
$wallet = bos_page_start('Beyond Market', 'Marketplace Listing', 'View a Beyond Market product.');
$id = max(0, (int) ($_GET['id'] ?? 0));
$listing = null;
try {
    $statement = beyond_db()->prepare("SELECT id,title,short_description,description,item_type,listing_type,price_cash,price_bits,currency,status,published_at FROM listings WHERE id=? AND status IN ('active','sold') LIMIT 1");
    $statement->execute([$id]);
    $listing = $statement->fetch() ?: null;
} catch (Throwable $exception) {
    $listing = null;
}
$isFree = $listing && (float) ($listing['price_cash'] ?? 0) <= 0 && (int) ($listing['price_bits'] ?? 0) <= 0;
?>
<main class="bos-main listing-main">
<?php if (!$listing): ?>
  <section class="bos-hero listing-missing"><span class="bos-kicker">Beyond Market</span><h1>Listing unavailable.</h1><p>This item may have ended, moved or not yet been published.</p><div class="bos-actions"><a class="bos-btn" href="<?=e(beyond_url('beyond-market/'))?>">Return to the market</a></div></section>
<?php else: ?>
  <?php if (!empty($_GET['created'])): ?><div class="created-notice">✓ Your listing is live in Beyond Market.</div><?php endif; ?>
  <nav class="listing-breadcrumb"><a href="<?=e(beyond_url('beyond-market/'))?>">Beyond Market</a><span>›</span><a href="<?=e(beyond_url('beyond-market/#live-listings'))?>">Live listings</a><span>›</span><b><?=e((string)$listing['title'])?></b></nav>
  <section class="listing-layout"><div class="listing-gallery"><div class="listing-art"><span><?=$listing['item_type']==='digital'?'▥':($listing['item_type']==='physical'?'□':'✦')?></span><small>BEYOND CREATOR MARKET</small></div><p>Product preview</p></div><div class="listing-details"><span class="bos-kicker"><?=e(ucfirst((string)$listing['listing_type']))?> · <?=e(ucfirst((string)$listing['item_type']))?></span><h1><?=e((string)$listing['title'])?></h1><p class="listing-description"><?=nl2br(e((string)($listing['description'] ?: $listing['short_description'])))?></p><div class="listing-price"><?php if($isFree):?><strong>Free</strong><span>Digital community download</span><?php else:?><strong><?php if((int)($listing['price_bits']??0)>0):?><?=number_format((int)$listing['price_bits'])?> bit$<?php endif;?><?php if((float)($listing['price_cash']??0)>0):?><?=((int)($listing['price_bits']??0)>0?' or ':'')?>$<?=number_format((float)$listing['price_cash'],2)?> <?=e((string)$listing['currency'])?><?php endif;?></strong><span>Secure Beyond Market checkout</span><?php endif;?></div><div class="listing-actions"><?php if($isFree):?><a class="bos-btn" href="checkout.php?id=<?=$id?>&amp;method=free">Get free download</a><?php else:?><?php if((int)($listing['price_bits']??0)>0):?><a class="bos-btn" href="checkout.php?id=<?=$id?>&amp;method=bits">Buy with bit$</a><?php endif;?><?php if((float)($listing['price_cash']??0)>0):?><a class="bos-btn secondary" href="checkout.php?id=<?=$id?>&amp;method=stripe">Pay with Stripe</a><?php endif;?><?php endif;?><button class="watch-listing" id="watchListing" type="button">♡ Add to watchlist</button></div><div class="buyer-points"><span>✓ Original creator listing</span><span>✓ Wallet-connected checkout</span><span>✓ Digital delivery tracking</span></div><p class="listing-id">Listing #<?=number_format($id)?> · Published <?=e((string)($listing['published_at']??'recently'))?></p></div></section>
<?php endif; ?>
</main>
