3bd}.buyer-points{display:grid;gap:8px;margin:22px 0;color:#aeb5cd;font-size:.82rem}.listing-id{color:#747d9d;font-size:.72rem}.listing-missing{background:linear-gradient(135deg,#171a3d,#40204f)}
@media(max-width:850px){.listing-layout{grid-template-columns:1fr}.listing-art{min-height:360px}}@media(max-width:560px){.listing-main{width:min(100% - 18px,1180px)}.listing-gallery,.listing-details{padding:18px 14px}.listing-art{min-height:300px}}
</style>
<script>document.getElementById('watchListing')?.addEventListener('click',event=>{const button=event.currentTarget;button.classList.toggle('saved');button.textContent=button.classList.contains('saved')?'♥ Watching':'♡ Add to watchlist'});</script>
<?php bos_page_end(); ?>
